import (
	"encoding/json"
	"fmt"
	"strings"

	"github.com/PuerkitoBio/goquery"
	"github.com/valyala/fasthttp"
)

// FetchURLPreview handles POST requests to fetch URL preview data
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Set response content type
	ctx.SetContentType("application/json")

	// Only accept POST requests
	if string(ctx.Method()) != "POST" {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		json.NewEncoder(ctx).Encode(map[string]string{
			"error": "Only POST method is allowed",
		})
		return
	}

	// Parse JSON body
	var requestBody struct {
		URL string `json:"url"`
	}

	if err := json.Unmarshal(ctx.PostBody(), &requestBody); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(map[string]string{
			"error": "Invalid JSON body: url field is required",
		})
		return
	}

	// Validate URL
	if requestBody.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(map[string]string{
			"error": "URL field is required",
		})
		return
	}

	// Create fasthttp client with dual stack support
	client := &fasthttp.Client{
		Dial: fasthttp.DialDualStack,
	}

	// Fetch the URL with redirects
	req := &fasthttp.Request{}
	req.Header.SetMethod("GET")
	req.SetRequestURI(requestBody.URL)

	statusCode, body, err := client.DoRedirects(req, requestBody.URL, 10)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(map[string]string{
			"error": fmt.Sprintf("Failed to fetch URL: %v", err),
		})
		return
	}

	// Check if request was successful
	if statusCode != fasthttp.StatusOK {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(map[string]string{
			"error": fmt.Sprintf("Failed to fetch URL: HTTP status %d", statusCode),
		})
		return
	}

	// Parse HTML to extract title and description
	title, description, err := extractMetadata(body)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(map[string]string{
			"error": fmt.Sprintf("Failed to parse HTML: %v", err),
		})
		return
	}

	// Return successful response
	ctx.SetStatusCode(fasthttp.StatusOK)
	json.NewEncoder(ctx).Encode(map[string]interface{}{
		"title":       title,
		"description": description,
		"url":         requestBody.URL,
	})
}

// extractMetadata extracts title and meta description from HTML content
func extractMetadata(htmlContent []byte) (string, string, error) {
	// Use goquery for HTML parsing
	doc, err := goquery.NewDocumentFromReader(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", "", err
	}

	// Extract title - prioritize og:title, then regular title
	title := doc.Find("meta[property='og:title']").AttrOr("content", "")
	if title == "" {
		title = doc.Find("title").Text()
	}

	// Extract description - prioritize og:description, then regular description
	description := doc.Find("meta[property='og:description']").AttrOr("content", "")
	if description == "" {
		description = doc.Find("meta[name='description']").AttrOr("content", "")
	}

	return strings.TrimSpace(title), strings.TrimSpace(description), nil
}

func main() {
	// Register the handler
	fasthttp.Post("/api/preview", FetchURLPreview)

	// Start the server
	fmt.Println("Server starting on :8080...")
	if err := fasthttp.ListenAndServe(":8080", nil); err != nil {
		fmt.Printf("Server error: %v\n", err)
	}
}

